const products = input[0]?.rows || [];
const movements = input[1]?.rows || [];

const organizedProducts = products.map(product => {
  const movement = movements.find(m => m.product_name === product.product_name);

  const currentStock = Number(product.current_stock || 0);
  const minimumStock = Number(product.minimum_stock || 0);
  const avgDailyDemand = Number(movement?.avg_daily_demand || 0);
  const totalSold7Days = Number(movement?.total_sold_7_days || 0);

  const daysBeforeRupture =
    avgDailyDemand > 0 ? Math.floor(currentStock / avgDailyDemand) : 999;

  const recommendedOrderQuantity = Math.max(
    0,
    Math.ceil((avgDailyDemand * 7) + minimumStock - currentStock)
  );

  return {
    product_id: product.id,
    product_name: product.product_name,
    category: product.category,
    current_stock: currentStock,
    minimum_stock: minimumStock,
    supplier_name: product.supplier_name,
    supplier_email: product.supplier_email,
    total_sold_7_days: totalSold7Days,
    avg_daily_demand: avgDailyDemand,
    days_before_rupture: daysBeforeRupture,
    recommended_order_quantity: recommendedOrderQuantity
  };
});

return {
  products: organizedProducts,
  productsJson: JSON.stringify(organizedProducts)
};

