// 2. L'arme secrète : Une fonction qui transforme tout en tableau
function forceArray(val) {
  if (!val) return []; // Si c'est null ou undefined -> []
  if (Array.isArray(val)) return val; // Si c'est déjà un tableau -> on le garde
  if (typeof val === 'object') return [val]; // SI C'EST L'OBJET DE VOTRE AGENT -> on le met dans un tableau : [{...}]
  return [];
}

// 3. On applique la fonction
